import { useEffect, useState } from 'react';
import { AlertTriangle, Sparkles, X } from 'lucide-react';
import { FormInput } from '../../../../components/ui/FormInput';
import { LoadingButton } from '../../../../components/ui/LoadingButton';
import type { KBForeshadow, KBForeshadowSuggestion, UpdateKBForeshadowInput } from './types';
import { FORESHADOW_STATUS_LABELS, FORESHADOW_STATUS_ORDER } from './types';

interface KBForeshadowDetailProps {
  foreshadow: KBForeshadow;
  saving?: boolean;
  onClose: () => void;
  onSave: (payload: UpdateKBForeshadowInput) => void | Promise<void>;
  onConfirmSuggestion: (suggestion: KBForeshadowSuggestion) => void | Promise<void>;
}

interface FormState {
  name: string;
  summary: string;
  quote: string;
  status: KBForeshadow['status'];
  expectedResolveChapterId: string;
  resolvedChapterId: string;
  resolveNote: string;
}

function buildState(foreshadow: KBForeshadow): FormState {
  return {
    name: foreshadow.name,
    summary: foreshadow.summary,
    quote: foreshadow.quote,
    status: foreshadow.status,
    expectedResolveChapterId: foreshadow.expectedResolveChapterId ?? '',
    resolvedChapterId: foreshadow.resolvedChapterId ?? '',
    resolveNote: foreshadow.resolveNote ?? '',
  };
}

export default function KBForeshadowDetail({
  foreshadow,
  saving = false,
  onClose,
  onSave,
  onConfirmSuggestion,
}: KBForeshadowDetailProps) {
  const [form, setForm] = useState<FormState>(() => buildState(foreshadow));
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setForm(buildState(foreshadow));
    setError(null);
  }, [foreshadow]);

  const handleSubmit = async () => {
    if (form.status === 'resolved' && (!form.resolvedChapterId.trim() || !form.resolveNote.trim())) {
      setError('已回收状态需要填写回收章节和回收说明');
      return;
    }

    setError(null);

    await onSave({
      name: form.name,
      summary: form.summary,
      quote: form.quote,
      status: form.status,
      expectedResolveChapterId: form.expectedResolveChapterId || undefined,
      resolvedChapterId: form.resolvedChapterId || undefined,
      resolveNote: form.resolveNote || undefined,
    });
  };

  return (
    <div className="flex h-full flex-col bg-white">
      <div className="flex items-center justify-between border-b border-[var(--color-border)] p-4">
        <div>
          <h2 className="text-lg font-semibold text-[var(--color-ink)]">伏笔详情</h2>
          <p className="mt-1 text-xs text-[var(--color-ink-light)]">埋设章节 {foreshadow.plantedChapterId}</p>
        </div>
        <button
          type="button"
          aria-label="关闭"
          onClick={onClose}
          className="rounded-md p-1.5 text-[var(--color-ink-light)] transition-colors hover:bg-[var(--color-parchment)] hover:text-[var(--color-ink)]"
        >
          <X size={18} />
        </button>
      </div>

      <div className="flex-1 space-y-5 overflow-y-auto p-4">
        {foreshadow.notifyState.warned && (
          <div className="flex items-center gap-2 rounded-md border border-[var(--color-error)]/20 bg-[var(--color-error)]/10 px-3 py-2 text-sm text-[var(--color-error)]">
            <AlertTriangle size={16} />
            该伏笔已超出预期回收进度，请尽快处理。
          </div>
        )}

        <FormInput
          id="foreshadow-name"
          label="名称"
          value={form.name}
          onChange={(value) => setForm((current) => ({ ...current, name: value }))}
        />

        <div>
          <label htmlFor="foreshadow-summary" className="mb-1.5 block text-sm font-medium text-ink-light">
            摘要
          </label>
          <textarea
            id="foreshadow-summary"
            value={form.summary}
            onChange={(event) => setForm((current) => ({ ...current, summary: event.target.value }))}
            className="input-base min-h-24 resize-y"
          />
        </div>

        <div>
          <label htmlFor="foreshadow-quote" className="mb-1.5 block text-sm font-medium text-ink-light">
            原文引用
          </label>
          <textarea
            id="foreshadow-quote"
            value={form.quote}
            onChange={(event) => setForm((current) => ({ ...current, quote: event.target.value }))}
            className="input-base min-h-24 resize-y"
          />
        </div>

        <FormInput
          id="foreshadow-planted-chapter"
          label="埋设章节"
          value={foreshadow.plantedChapterId}
          onChange={() => undefined}
          disabled
        />

        <div>
          <label htmlFor="foreshadow-status" className="mb-1.5 block text-sm font-medium text-ink-light">
            状态
          </label>
          <select
            id="foreshadow-status"
            value={form.status}
            onChange={(event) => setForm((current) => ({ ...current, status: event.target.value as KBForeshadow['status'] }))}
            className="input-base"
          >
            {FORESHADOW_STATUS_ORDER.map((status) => (
              <option key={status} value={status}>
                {FORESHADOW_STATUS_LABELS[status]}
              </option>
            ))}
          </select>
        </div>

        <FormInput
          id="foreshadow-expected-chapter"
          label="预期回收章节"
          value={form.expectedResolveChapterId}
          onChange={(value) => setForm((current) => ({ ...current, expectedResolveChapterId: value }))}
        />

        <FormInput
          id="foreshadow-resolved-chapter"
          label="回收章节"
          value={form.resolvedChapterId}
          onChange={(value) => setForm((current) => ({ ...current, resolvedChapterId: value }))}
        />

        <div>
          <label htmlFor="foreshadow-resolve-note" className="mb-1.5 block text-sm font-medium text-ink-light">
            回收说明
          </label>
          <textarea
            id="foreshadow-resolve-note"
            value={form.resolveNote}
            onChange={(event) => setForm((current) => ({ ...current, resolveNote: event.target.value }))}
            className="input-base min-h-24 resize-y"
          />
        </div>

        {error && <p className="text-sm text-[var(--color-error)]">{error}</p>}

        <section className="space-y-3 rounded-lg border border-[var(--color-border)] bg-[var(--color-parchment)]/40 p-4">
          <div className="flex items-center gap-2 text-sm font-semibold text-[var(--color-ink)]">
            <Sparkles size={16} className="text-[var(--color-amber)]" />
            AI 建议
          </div>

          {foreshadow.aiSuggestions.length === 0 ? (
            <p className="text-sm text-[var(--color-ink-light)]">暂无 AI 建议</p>
          ) : (
            foreshadow.aiSuggestions.map((suggestion) => (
              <div key={`${suggestion.chapterId}-${suggestion.createdAt}`} className="rounded-md bg-white p-3 shadow-sm">
                <p className="text-sm text-[var(--color-ink)]">{suggestion.message}</p>
                <div className="mt-2 flex items-center justify-between gap-3 text-xs text-[var(--color-ink-light)]">
                  <span>建议章节 {suggestion.chapterId}</span>
                  <button
                    type="button"
                    onClick={() => onConfirmSuggestion(suggestion)}
                    className="rounded-md bg-[var(--color-amber)] px-3 py-1.5 font-medium text-white transition-colors hover:bg-[var(--color-amber-dark)]"
                  >
                    确认 AI 建议
                  </button>
                </div>
              </div>
            ))
          )}
        </section>
      </div>

      <div className="border-t border-[var(--color-border)] p-4">
        <LoadingButton loading={saving} loadingText="保存中..." type="button" onClick={handleSubmit}>
          保存伏笔
        </LoadingButton>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Search, Filter, List, Network, CheckCircle2, Loader2 } from 'lucide-react';
import type { KBLocation, KBLocationTreeNode, LocationType } from './types';
import { LOCATION_TYPE_LABELS } from './types';
import KBLocationCard from './KBLocationCard';

interface KBLocationListProps {
  locations: KBLocation[];
  tree: KBLocationTreeNode[];
  loading: boolean;
  search?: string;
  viewMode?: 'list' | 'tree';
  selectedIds?: string[];
  onLocationClick?: (location: KBLocation) => void;
  onSelectionChange?: (ids: string[]) => void;
  onSearchChange?: (value: string) => void;
  onTypeFilterChange?: (value: LocationType | undefined) => void;
  onConfirm?: (id: string) => void;
  onReject?: (id: string) => void;
  onBulkConfirm?: (ids: string[]) => void;
}

const NEW_DISCOVERY_THRESHOLD_HOURS = 24;

export default function KBLocationList({
  locations,
  tree,
  loading,
  search = '',
  viewMode = 'list',
  selectedIds = [],
  onLocationClick,
  onSelectionChange,
  onSearchChange,
  onTypeFilterChange,
  onConfirm,
  onReject,
  onBulkConfirm,
}: KBLocationListProps) {
  const [localSearch, setLocalSearch] = useState(search);
  const [typeFilter, setTypeFilter] = useState<LocationType | ''>('');

  const handleSearchChange = (value: string) => {
    setLocalSearch(value);
    onSearchChange?.(value);
  };

  const handleTypeChange = (value: LocationType | '') => {
    setTypeFilter(value);
    onTypeFilterChange?.(value === '' ? undefined : value);
  };

  const handleSelect = (id: string, selected: boolean) => {
    if (selected) {
      onSelectionChange?.([...selectedIds, id]);
    } else {
      onSelectionChange?.(selectedIds.filter(i => i !== id));
    }
  };

  const handleBulkConfirm = () => {
    onBulkConfirm?.(selectedIds);
  };

  const newDiscoveryCount = locations.filter(loc => {
    if (loc.source !== 'ai' || loc.confirmed) return false;
    const createdAt = new Date(loc.createdAt);
    const now = new Date();
    const diffHours = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60);
    return diffHours < NEW_DISCOVERY_THRESHOLD_HOURS;
  }).length;

  const renderTreeNode = (node: KBLocationTreeNode, depth = 0): React.ReactNode => {
    return (
      <div key={node.id} style={{ marginLeft: depth * 24 }}>
        <KBLocationCard
          location={node}
          parentLocations={locations}
          selected={selectedIds.includes(node.id)}
          onClick={onLocationClick}
          onSelect={onSelectionChange ? handleSelect : undefined}
          onConfirm={onConfirm}
          onReject={onReject}
        />
        {node.children.length > 0 && (
          <div className="mt-2 space-y-2">
            {node.children.map(child => renderTreeNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  if (loading && locations.length === 0) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="animate-spin text-[var(--color-amber)]" size={24} />
        <span className="ml-2 text-[var(--color-ink-light)]">加载中...</span>
      </div>
    );
  }

  if (locations.length === 0 && !search && !typeFilter) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-[var(--color-ink-light)]">
        <p>暂无地点</p>
        {newDiscoveryCount > 0 && (
          <span className="mt-2 px-3 py-1 text-sm bg-green-100 text-green-700 rounded-full">
            新发现 {newDiscoveryCount}
          </span>
        )}
      </div>
    );
  }

  if (locations.length === 0 && (search || typeFilter)) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-[var(--color-ink-light)]">
        <p>未找到匹配「{search || typeFilter}」的地点</p>
      </div>
    );
  }

  const filteredLocations = locations.filter(loc => {
    if (localSearch && !loc.name.toLowerCase().includes(localSearch.toLowerCase())) {
      return false;
    }
    if (typeFilter && loc.locationType !== typeFilter) {
      return false;
    }
    return true;
  });

  const unconfirmedCount = filteredLocations.filter(l => l.source === 'ai' && !l.confirmed).length;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4">
        <div className="relative flex-1">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--color-ink-light)]" />
          <input
            type="text"
            placeholder="搜索地点名称..."
            value={localSearch}
            onChange={(e) => handleSearchChange(e.target.value)}
            className="w-full pl-9 pr-4 py-2 border border-[var(--color-border)] rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-amber/20 focus:border-amber"
          />
        </div>

        <select
          value={typeFilter}
          onChange={(e) => handleTypeChange(e.target.value as LocationType | '')}
          className="px-3 py-2 border border-[var(--color-border)] rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-amber/20"
          aria-label="筛选地点类型"
        >
          <option value="">全部类型</option>
          {Object.entries(LOCATION_TYPE_LABELS).map(([value, label]) => (
            <option key={value} value={value}>{label}</option>
          ))}
        </select>

        <div className="flex items-center gap-1 p-1 bg-gray-100 rounded-lg">
          <button
            onClick={() => {}}
            className={`p-2 rounded ${viewMode === 'list' ? 'bg-white shadow text-amber' : 'text-[var(--color-ink-light)]'}`}
            aria-label="列表视图"
          >
            <List size={16} />
          </button>
          <button
            onClick={() => {}}
            className={`p-2 rounded ${viewMode === 'tree' ? 'bg-white shadow text-amber' : 'text-[var(--color-ink-light)]'}`}
            aria-label="树状视图"
          >
            <Network size={16} />
          </button>
        </div>
      </div>

      {newDiscoveryCount > 0 && (
        <div className="flex items-center gap-2">
          <span className="px-3 py-1 text-sm bg-green-100 text-green-700 rounded-full">
            新发现 {newDiscoveryCount}
          </span>
          {unconfirmedCount > 0 && (
            <span className="text-sm text-[var(--color-ink-light)]">
              待确认 {unconfirmedCount}
            </span>
          )}
        </div>
      )}

      {selectedIds.length > 0 && (
        <div className="flex items-center justify-between p-3 bg-amber-light/20 border border-amber/30 rounded-md">
          <span className="text-sm font-medium text-[var(--color-ink)]">
            已选择{selectedIds.length}项
          </span>
          <button
            onClick={handleBulkConfirm}
            className="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-white bg-amber rounded-md hover:bg-amber/90 transition-colors"
          >
            <CheckCircle2 size={14} />
            批量确认
          </button>
        </div>
      )}

      <div className="space-y-2">
        {viewMode === 'tree' ? (
          tree.map(node => renderTreeNode(node))
        ) : (
          filteredLocations.map(location => (
            <KBLocationCard
              key={location.id}
              location={location}
              parentLocations={locations}
              selected={selectedIds.includes(location.id)}
              onClick={onLocationClick}
              onSelect={onSelectionChange ? handleSelect : undefined}
              onConfirm={onConfirm}
              onReject={onReject}
            />
          ))
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { MapPin, Loader2, AlertCircle } from 'lucide-react';
import { useKBLocation } from '../../hooks/useKBLocation';
import KBLocationList from './KBLocationList';
import KBLocationDetail from './KBLocationDetail';
import type { KBLocation, KBLocationReferences } from './types';

interface KBLocationPanelProps {
  projectId: string;
  selectedLocationId?: string;
}

export default function KBLocationPanel({ projectId, selectedLocationId }: KBLocationPanelProps) {
  const {
    locations,
    tree,
    loading,
    error,
    search,
    locationType,
    selectedIds,
    confirmDialogOpen,
    bulkConfirmDialogOpen,
    mergeDialogOpen,
    pendingConfirmId,
    pendingBulkConfirmIds,
    pendingMergeSourceId,
    locationsMap,
    handleSearchChange,
    handleTypeFilterChange,
    handleConfirm,
    handleReject,
    handleBulkConfirm,
    handleMerge,
    setConfirmDialogOpen,
    setBulkConfirmDialogOpen,
    setMergeDialogOpen,
    confirmLocation,
    bulkConfirm,
    mergeLocation,
    setSelectedIds,
  } = useKBLocation(projectId);

  const selectedLocation = selectedLocationId ? locationsMap[selectedLocationId] : null;
  const parentLocation = selectedLocation?.parentId ? locationsMap[selectedLocation.parentId] : null;

  const [detailLoading, setDetailLoading] = useState(false);
  const [references, setReferences] = useState<KBLocationReferences | null>(null);

  const handleLocationClick = async (location: KBLocation) => {
    setSelectedIds([location.id]);

    if (location.chapterIds.length > 0 || location.characterIds.length > 0) {
      setDetailLoading(true);
    }
  };

  const handleCloseDetail = () => {
    setSelectedIds([]);
  };

  const handleConfirmDialogConfirm = async () => {
    if (pendingConfirmId) {
      await confirmLocation(pendingConfirmId);
    }
    setConfirmDialogOpen(false);
  };

  const handleBulkConfirmDialogConfirm = async () => {
    await bulkConfirm(pendingBulkConfirmIds);
    setBulkConfirmDialogOpen(false);
  };

  const handleMergeDialogConfirm = async () => {
    if (pendingMergeSourceId) {
      await mergeLocation(pendingMergeSourceId, '');
    }
    setMergeDialogOpen(false);
  };

  const newDiscoveryCount = locations.filter(loc => {
    if (loc.source !== 'ai' || loc.confirmed) return false;
    const createdAt = new Date(loc.createdAt);
    const now = new Date();
    const diffHours = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60);
    return diffHours < 24;
  }).length;

  return (
    <div className="h-full flex flex-col bg-[var(--color-parchment)]">
      <div className="flex items-center justify-between p-4 border-b border-[var(--color-border)] bg-white">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-amber/10 rounded-lg flex items-center justify-center">
            <MapPin size={20} className="text-amber" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-[var(--color-ink)]">地点知识库</h1>
            {newDiscoveryCount > 0 && (
              <span className="text-sm text-green-600 font-medium">
                新发现 {newDiscoveryCount}
              </span>
            )}
          </div>
        </div>
      </div>

      {error && (
        <div className="mx-4 mt-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2 text-red-700">
          <AlertCircle size={16} />
          <span>{error}</span>
        </div>
      )}

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 ${selectedLocation ? 'border-r border-[var(--color-border)]' : ''}`}>
          <KBLocationList
            locations={locations}
            tree={tree}
            loading={loading}
            search={search}
            viewMode="list"
            selectedIds={selectedIds}
            onLocationClick={handleLocationClick}
            onSelectionChange={setSelectedIds}
            onSearchChange={handleSearchChange}
            onTypeFilterChange={handleTypeFilterChange}
            onConfirm={handleConfirm}
            onReject={handleReject}
            onBulkConfirm={handleBulkConfirm}
          />
        </div>

        {selectedLocation && (
          <div className="w-96 flex-shrink-0 overflow-hidden">
            <KBLocationDetail
              location={selectedLocation}
              parentLocation={parentLocation}
              references={references || undefined}
              onClose={handleCloseDetail}
              onConfirm={handleConfirm}
              onReject={handleReject}
              onMerge={handleMerge}
            />
          </div>
        )}
      </div>

      {confirmDialogOpen && (
        <div className="fixed inset-0 bg-black/30 flex items-center justify-center z-50" onClick={() => setConfirmDialogOpen(false)}>
          <div className="bg-white rounded-lg shadow-xl w-full max-w-sm p-6" onClick={(e) => e.stopPropagation()}>
            <h2 className="text-lg font-bold text-[var(--color-ink)] mb-2">确认地点</h2>
            <p className="text-[var(--color-ink-light)] mb-4">确定要确认这个地点吗？</p>
            <div className="flex justify-end gap-3">
              <button
                onClick={() => setConfirmDialogOpen(false)}
                className="px-4 py-2 text-sm font-medium text-[var(--color-ink)] bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
              >
                取消
              </button>
              <button
                onClick={handleConfirmDialogConfirm}
                className="px-4 py-2 text-sm font-medium text-white bg-amber rounded-lg hover:bg-amber/90 transition-colors"
              >
                确认
              </button>
            </div>
          </div>
        </div>
      )}

      {bulkConfirmDialogOpen && (
        <div className="fixed inset-0 bg-black/30 flex items-center justify-center z-50" onClick={() => setBulkConfirmDialogOpen(false)}>
          <div className="bg-white rounded-lg shadow-xl w-full max-w-sm p-6" onClick={(e) => e.stopPropagation()}>
            <h2 className="text-lg font-bold text-[var(--color-ink)] mb-2">批量确认</h2>
            <p className="text-[var(--color-ink-light)] mb-4">
              确定要确认选中的 {pendingBulkConfirmIds.length} 个地点吗？
            </p>
            <div className="flex justify-end gap-3">
              <button
                onClick={() => setBulkConfirmDialogOpen(false)}
                className="px-4 py-2 text-sm font-medium text-[var(--color-ink)] bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
              >
                取消
              </button>
              <button
                onClick={handleBulkConfirmDialogConfirm}
                className="px-4 py-2 text-sm font-medium text-white bg-amber rounded-lg hover:bg-amber/90 transition-colors"
              >
                确认
              </button>
            </div>
          </div>
        </div>
      )}

      {mergeDialogOpen && (
        <div className="fixed inset-0 bg-black/30 flex items-center justify-center z-50" onClick={() => setMergeDialogOpen(false)}>
          <div className="bg-white rounded-lg shadow-xl w-full max-w-sm p-6" onClick={(e) => e.stopPropagation()}>
            <h2 className="text-lg font-bold text-[var(--color-ink)] mb-2">合并地点</h2>
            <p className="text-[var(--color-ink-light)] mb-4">
              选择要合并到的目标地点
            </p>
            <div className="flex justify-end gap-3">
              <button
                onClick={() => setMergeDialogOpen(false)}
                className="px-4 py-2 text-sm font-medium text-[var(--color-ink)] bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
              >
                取消
              </button>
              <button
                onClick={handleMergeDialogConfirm}
                className="px-4 py-2 text-sm font-medium text-white bg-amber rounded-lg hover:bg-amber/90 transition-colors"
              >
                确认合并
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import {
  AlertCircle,
  CheckCircle2,
  Loader2,
  Minus,
  RotateCcw,
  XCircle,
} from 'lucide-react';
import type { ParserChapterStatusValue } from './types';

interface ChapterParseStatusProps {
  status: ParserChapterStatusValue;
  failureReason?: string | null;
  chapterTitle?: string;
  onRetry?: () => void;
  className?: string;
}

const normalizeStatus = (status: ParserChapterStatusValue) => {
  if (status === 'empty' || status === 'none') {
    return 'no_content';
  }

  if (status === 'queued' || status === 'cancelled') {
    return 'pending';
  }

  return status;
};

const getStatusLabel = (status: ParserChapterStatusValue) => {
  switch (normalizeStatus(status)) {
    case 'parsed':
      return '已解析';
    case 'parsing':
      return '解析中';
    case 'pending':
      return '待解析';
    case 'failed':
      return '解析失败';
    default:
      return '无内容';
  }
};

const getStatusIcon = (status: ParserChapterStatusValue) => {
  switch (normalizeStatus(status)) {
    case 'parsed':
      return <CheckCircle2 size={14} className="text-success" aria-label="已解析" />;
    case 'parsing':
      return <Loader2 size={14} className="animate-spin text-amber" aria-label="解析中" />;
    case 'pending':
      return <AlertCircle size={14} className="text-warning" aria-label="待解析" />;
    case 'failed':
      return <XCircle size={14} className="text-error" aria-label="解析失败" />;
    default:
      return <Minus size={14} className="text-ink-light/60" aria-label="无内容" />;
  }
};

export default function ChapterParseStatus({
  status,
  failureReason,
  chapterTitle,
  onRetry,
  className = '',
}: ChapterParseStatusProps) {
  if (normalizeStatus(status) === 'failed' && onRetry) {
    return (
      <button
        type="button"
        onClick={onRetry}
        title={failureReason ?? undefined}
        aria-label={`重试解析 ${chapterTitle ?? '章节'}`}
        className={`inline-flex items-center gap-1 rounded p-1 text-error hover:bg-error/10 focus:outline-none focus:ring-2 focus:ring-amber/20 ${className}`}
      >
        {getStatusIcon(status)}
        <RotateCcw size={12} className="text-error/80" aria-hidden="true" />
      </button>
    );
  }

  return (
    <span className={`inline-flex items-center ${className}`} title={failureReason ?? undefined}>
      {getStatusIcon(status)}
    </span>
  );
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import KBLocationList from '../KBLocation/KBLocationList';
import type { KBLocation, KBLocationTreeNode } from '../KBLocation/types';

vi.mock('../hooks/useKBLocation');

const createKBLocation = (overrides: Partial<KBLocation> = {}): KBLocation => ({
  id: '1',
  projectId: 'project1',
  source: 'ai',
  confirmed: false,
  name: 'Beijing',
  aliases: [],
  locationType: 'city',
  characterIds: [],
  chapterIds: [],
  createdAt: '2024-01-15T10:00:00Z',
  updatedAt: '2024-01-15T10:00:00Z',
  ...overrides,
});

const createTreeNode = (overrides: Partial<KBLocationTreeNode> & { id: string; name: string }): KBLocationTreeNode => ({
  ...createKBLocation({ id: overrides.id, name: overrides.name }),
  children: overrides.children || [],
  ...overrides,
});

describe('KBLocationList', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should render search input', () => {
    const locations = [createKBLocation()];
    const tree = [createTreeNode({ id: '1', name: 'Beijing' })];

    render(
      <KBLocationList
        locations={locations}
        tree={tree}
        loading={false}
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    expect(screen.getByPlaceholderText('搜索地点名称...')).toBeInTheDocument();
  });

  it('should call onSearchChange when search input changes', async () => {
    const user = userEvent.setup();
    const onSearchChange = vi.fn();
    const locations = [createKBLocation()];
    const tree = [createTreeNode({ id: '1', name: 'Beijing' })];

    render(
      <KBLocationList
        locations={locations}
        tree={tree}
        loading={false}
        onLocationClick={vi.fn()}
        onSearchChange={onSearchChange}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    await user.type(screen.getByPlaceholderText('搜索地点名称...'), 'Beijing');
    expect(onSearchChange).toHaveBeenCalledWith('Beijing');
  });

  it('should render type filter dropdown', () => {
    const locations = [createKBLocation()];
    const tree = [createTreeNode({ id: '1', name: 'Beijing' })];

    render(
      <KBLocationList
        locations={locations}
        tree={tree}
        loading={false}
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    expect(screen.getByRole('combobox')).toBeInTheDocument();
  });

  it('should render location cards', () => {
    const locations = [
      createKBLocation({ id: '1', name: 'Beijing' }),
      createKBLocation({ id: '2', name: 'Shanghai' }),
    ];
    const tree = [
      createTreeNode({ id: '1', name: 'Beijing' }),
      createTreeNode({ id: '2', name: 'Shanghai' }),
    ];

    render(
      <KBLocationList
        locations={locations}
        tree={tree}
        loading={false}
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    expect(screen.getByText('Beijing')).toBeInTheDocument();
    expect(screen.getByText('Shanghai')).toBeInTheDocument();
  });

  it('should show loading state', () => {
    render(
      <KBLocationList
        locations={[]}
        tree={[]}
        loading={true}
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    expect(screen.getByText('加载中...')).toBeInTheDocument();
  });

  it('should show empty state when no locations', () => {
    render(
      <KBLocationList
        locations={[]}
        tree={[]}
        loading={false}
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    expect(screen.getByText('暂无地点')).toBeInTheDocument();
  });

  it('should show empty state with search results', () => {
    render(
      <KBLocationList
        locations={[]}
        tree={[]}
        loading={false}
        search="NonExistent"
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
        onConfirm={vi.fn()}
        onReject={vi.fn()}
        onBulkConfirm={vi.fn()}
      />
    );

    expect(screen.getByText('未找到匹配「NonExistent」的地点')).toBeInTheDocument();
  });

  it('should render tree view toggle button', () => {
    const locations = [createKBLocation()];
    const tree = [createTreeNode({ id: '1', name: 'Beijing' })];

    render(
      <KBLocationList
        locations={locations}
        tree={tree}
        loading={false}
        onLocationClick={vi.fn()}
        onSearchChange={vi.fn()}
        onTypeFilterChange={vi.fn()}
