import { useState, useEffect, useCallback } from 'react';
import { client } from '../../../api/client';
import type { KBFaction, FactionType, KBFactionReferences } from '../components/KBFaction/types';

const PAGE_SIZE = 20;

export interface UseKBFactionOptions {
  projectId: string;
  initialSearch?: string;
  initialTypeFilter?: FactionType | 'all';
}

export interface UseKBFactionReturn {
  factions: KBFaction[];
  loading: boolean;
  error: string | null;
  hasMore: boolean;
  search: string;
  setSearch: (search: string) => void;
  typeFilter: FactionType | 'all';
  setTypeFilter: (filter: FactionType | 'all') => void;
  selectedFaction: KBFaction | null;
  setSelectedFaction: (faction: KBFaction | null) => void;
  selectedFactionRefs: KBFactionReferences | null;
  loadingRefs: boolean;
  loadMore: () => Promise<void>;
  confirmFaction: (id: string) => Promise<void>;
  rejectFaction: (id: string) => Promise<void>;
  refetch: () => Promise<void>;
}

export function useKBFaction({
  projectId,
  initialSearch = '',
  initialTypeFilter = 'all',
}: UseKBFactionOptions): UseKBFactionReturn {
  const [factions, setFactions] = useState<KBFaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(false);
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState(initialSearch);
  const [typeFilter, setTypeFilter] = useState<FactionType | 'all'>(initialTypeFilter);
  const [selectedFaction, setSelectedFaction] = useState<KBFaction | null>(null);
  const [selectedFactionRefs, setSelectedFactionRefs] = useState<KBFactionReferences | null>(null);
  const [loadingRefs, setLoadingRefs] = useState(false);

  const buildQueryString = useCallback((pageNum: number, searchQuery: string, filter: FactionType | 'all') => {
    const params = new URLSearchParams();
    params.append('page', pageNum.toString());
    params.append('page_size', PAGE_SIZE.toString());
    if (searchQuery.trim()) {
      params.append('search', searchQuery.trim());
    }
    if (filter !== 'all') {
      params.append('faction_type', filter);
    }
    return params.toString();
  }, []);

  const fetchFactions = useCallback(async (pageNum: number, append = false) => {
    try {
      setLoading(true);
      setError(null);

      const queryString = buildQueryString(pageNum, search, typeFilter);
      const { data, error: apiError } = await client.GET(
        `/api/projects/${projectId}/knowledge-base/factions?${queryString}`
      );

      if (apiError) {
        throw new Error('Failed to fetch factions');
      }

      const response = data as { items: KBFaction[]; has_more: boolean };

      if (append) {
        setFactions(prev => [...prev, ...response.items]);
      } else {
        setFactions(response.items);
      }

      setHasMore(response.has_more);
      setPage(pageNum);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [buildQueryString, projectId, search, typeFilter]);

  const fetchFactionReferences = useCallback(async (factionId: string) => {
    try {
      setLoadingRefs(true);
      const { data, error: apiError } = await client.GET(
        `/api/projects/${projectId}/knowledge-base/factions/${factionId}/references`
      );

      if (apiError) {
        throw new Error('Failed to fetch faction references');
      }

      setSelectedFactionRefs(data as KBFactionReferences);
    } catch (err) {
      setSelectedFactionRefs(null);
    } finally {
      setLoadingRefs(false);
    }
  }, [projectId]);

  const confirmFaction = useCallback(async (id: string) => {
    const originalFactions = [...factions];
    setFactions(prev =>
      prev.map(f => (f.id === id ? { ...f, confirmed: true, source: 'manual' as const } : f))
    );

    if (selectedFaction?.id === id) {
      setSelectedFaction(prev => prev ? { ...prev, confirmed: true, source: 'manual' as const } : null);
    }

    try {
      const { error: apiError } = await client.POST(
        `/api/projects/${projectId}/knowledge-base/factions/${id}/confirm`
      );

      if (apiError) {
        throw new Error('Failed to confirm faction');
      }
    } catch {
      setFactions(originalFactions);
      if (selectedFaction?.id === id) {
        setSelectedFaction(prev => prev ? { ...prev, confirmed: false, source: 'ai' as const } : null);
      }
    }
  }, [factions, projectId, selectedFaction]);

  const rejectFaction = useCallback(async (id: string) => {
    const originalFactions = [...factions];
    setFactions(prev => prev.filter(f => f.id !== id));

    if (selectedFaction?.id === id) {
      setSelectedFaction(null);
      setSelectedFactionRefs(null);
    }

    try {
      const { error: apiError } = await client.DELETE(
        `/api/projects/${projectId}/knowledge-base/factions/${id}`
      );

      if (apiError) {
        throw new Error('Failed to reject faction');
      }
    } catch {
      setFactions(originalFactions);
    }
  }, [factions, projectId, selectedFaction]);

  const loadMore = useCallback(async () => {
    if (!hasMore || loading) return;
    await fetchFactions(page + 1, true);
  }, [hasMore, loading, page, fetchFactions]);

  const refetch = useCallback(async () => {
    await fetchFactions(1, false);
  }, [fetchFactions]);

  useEffect(() => {
    fetchFactions(1, false);
  }, [projectId, search, typeFilter]);

  useEffect(() => {
    if (selectedFaction) {
      fetchFactionReferences(selectedFaction.id);
    } else {
      setSelectedFactionRefs(null);
    }
  }, [selectedFaction, fetchFactionReferences]);

  return {
    factions,
    loading,
    error,
    hasMore,
    search,
    setSearch,
    typeFilter,
    setTypeFilter,
    selectedFaction,
    setSelectedFaction,
    selectedFactionRefs,
    loadingRefs,
    loadMore,
    confirmFaction,
    rejectFaction,
    refetch,
  };
}

import { useState, useEffect, useCallback } from 'react';
import { client } from '../../../api/client';
import type { 
  KBLocation, 
  KBLocationTreeNode, 
  KBLocationListResponse,
  KBLocationReferences,
  LocationType 
} from '../components/KBLocation/types';

interface UseKBLocationOptions {
  search?: string;
  locationType?: LocationType;
  confirmed?: boolean;
}

interface UseKBLocationReturn {
  locations: KBLocation[];
  tree: KBLocationTreeNode[];
  loading: boolean;
  error: string | null;
  hasMore: boolean;
  search: string;
  locationType: LocationType | undefined;
  confirmed: boolean | undefined;
  selectedIds: string[];
  confirmDialogOpen: boolean;
  bulkConfirmDialogOpen: boolean;
  mergeDialogOpen: boolean;
  pendingConfirmId: string | null;
  pendingBulkConfirmIds: string[];
  pendingMergeSourceId: string | null;
  locationsMap: Record<string, KBLocation>;
  setSearch: (search: string) => void;
  setLocationType: (type: LocationType | undefined) => void;
  setConfirmed: (confirmed: boolean | undefined) => void;
  setSelectedIds: (ids: string[]) => void;
  createLocation: (data: CreateKBLocationInput) => Promise<KBLocation | null>;
  updateLocation: (id: string, data: UpdateKBLocationInput) => Promise<void>;
  deleteLocation: (id: string) => Promise<void>;
  confirmLocation: (id: string) => Promise<void>;
  rejectLocation: (id: string) => Promise<void>;
  bulkConfirm: (ids: string[]) => Promise<void>;
  mergeLocation: (sourceId: string, targetId: string) => Promise<void>;
  fetchReferences: (id: string) => Promise<KBLocationReferences | null>;
  loadMore: () => Promise<void>;
  refetch: () => Promise<void>;
  setConfirmDialogOpen: (open: boolean) => void;
  setBulkConfirmDialogOpen: (open: boolean) => void;
  setMergeDialogOpen: (open: boolean) => void;
  setPendingConfirmId: (id: string | null) => void;
  setPendingBulkConfirmIds: (ids: string[]) => void;
  setPendingMergeSourceId: (id: string | null) => void;
  handleSearchChange: (value: string) => void;
  handleTypeFilterChange: (value: LocationType | undefined) => void;
  handleConfirm: (id: string) => void;
  handleReject: (id: string) => void;
  handleBulkConfirm: (ids: string[]) => void;
  handleMerge: (sourceId: string) => void;
}

interface CreateKBLocationInput {
  name: string;
  locationType: LocationType;
  parentId?: string;
  aliases?: string[];
  description?: string;
}

interface UpdateKBLocationInput {
  name?: string;
  locationType?: LocationType;
  parentId?: string | null;
  aliases?: string[];
  description?: string;
  remark?: string;
}

const PAGE_SIZE = 20;

export function useKBLocation(projectId: string, options: UseKBLocationOptions = {}): UseKBLocationReturn {
  const [locations, setLocations] = useState<KBLocation[]>([]);
  const [tree, setTree] = useState<KBLocationTreeNode[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(false);
  const [page, setPage] = useState(1);

  const [search, setSearch] = useState(options.search || '');
  const [locationType, setLocationType] = useState<LocationType | undefined>(options.locationType);
  const [confirmed, setConfirmed] = useState<boolean | undefined>(options.confirmed);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [confirmDialogOpen, setConfirmDialogOpen] = useState(false);
  const [bulkConfirmDialogOpen, setBulkConfirmDialogOpen] = useState(false);
  const [mergeDialogOpen, setMergeDialogOpen] = useState(false);
  const [pendingConfirmId, setPendingConfirmId] = useState<string | null>(null);
  const [pendingBulkConfirmIds, setPendingBulkConfirmIds] = useState<string[]>([]);
  const [pendingMergeSourceId, setPendingMergeSourceId] = useState<string | null>(null);

  const locationsMap = locations.reduce((acc, loc) => {
    acc[loc.id] = loc;
    return acc;
  }, {} as Record<string, KBLocation>);

  const buildQueryString = useCallback((pageNum: number, searchQuery: string, type: LocationType | undefined, conf: boolean | undefined) => {
    const params = new URLSearchParams();
    params.append('page', pageNum.toString());
    params.append('page_size', PAGE_SIZE.toString());
    if (searchQuery) {
      params.append('search', searchQuery);
    }
    if (type) {
      params.append('location_type', type);
    }
    if (conf !== undefined) {
      params.append('confirmed', conf.toString());
    }
    return params.toString();
  }, []);

  const buildTree = useCallback((flatLocations: KBLocation[]): KBLocationTreeNode[] => {
    const locationMap = new Map<string, KBLocationTreeNode>();
    const rootNodes: KBLocationTreeNode[] = [];

    flatLocations.forEach(loc => {
      locationMap.set(loc.id, { ...loc, children: [] });
    });

    flatLocations.forEach(loc => {
      const node = locationMap.get(loc.id)!;
      if (loc.parentId && locationMap.has(loc.parentId)) {
        const parent = locationMap.get(loc.parentId)!;
        parent.children.push(node);
      } else {
        rootNodes.push(node);
      }
    });

    return rootNodes;
  }, []);

  const fetchLocations = useCallback(async (pageNum: number, append = false) => {
    try {
      setLoading(true);
      setError(null);

      const queryString = buildQueryString(pageNum, search, locationType, confirmed);
      const { data, error: apiError } = await client.GET(`/api/projects/${projectId}/kb/location?${queryString}`);

      if (apiError) {
        throw new Error('Failed to fetch locations');
      }

      const response = data as KBLocationListResponse;

      if (append) {
        setLocations(prev => [...prev, ...response.items]);
      } else {
        setLocations(response.items);
      }

      setTree(buildTree(response.items));
      setHasMore(response.has_more);
      setPage(pageNum);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [projectId, search, locationType, confirmed, buildQueryString, buildTree]);

  useEffect(() => {
    fetchLocations(1, false);
  }, [projectId, search, locationType, confirmed]);

  const createLocation = useCallback(async (input: CreateKBLocationInput): Promise<KBLocation | null> => {
    try {
      const { data, error: apiError } = await client.POST(`/api/projects/${projectId}/kb/location`, {
        body: input,
      });

      if (apiError) {
        throw new Error('Failed to create location');
      }

      await fetchLocations(1, false);
      return data as KBLocation;
    } catch {
      return null;
    }
  }, [projectId, fetchLocations]);

  const updateLocation = useCallback(async (id: string, input: UpdateKBLocationInput): Promise<void> => {
    try {
      const { error: apiError } = await client.PATCH(`/api/projects/${projectId}/kb/location/${id}`, {
        body: input,
      });

      if (apiError) {
        throw new Error('Failed to update location');
      }

      await fetchLocations(1, false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }, [projectId, fetchLocations]);

  const deleteLocation = useCallback(async (id: string): Promise<void> => {
    try {
      const { error: apiError } = await client.DELETE(`/api/projects/${projectId}/kb/location/${id}`);

      if (apiError) {
        throw new Error('Failed to delete location');
      }

      await fetchLocations(1, false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }, [projectId, fetchLocations]);

  const confirmLocation = useCallback(async (id: string): Promise<void> => {
    try {
      const { error: apiError } = await client.POST(`/api/projects/${projectId}/kb/location/${id}/confirm`);

      if (apiError) {
        throw new Error('Failed to confirm location');
      }

      await fetchLocations(1, false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }, [projectId, fetchLocations]);

  const rejectLocation = useCallback(async (id: string): Promise<void> => {
    try {
      const { error: apiError } = await client.POST(`/api/projects/${projectId}/kb/location/${id}/reject`);

      if (apiError) {
        throw new Error('Failed to reject location');
      }

      await fetchLocations(1, false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }, [projectId, fetchLocations]);

  const bulkConfirm = useCallback(async (ids: string[]): Promise<void> => {
    try {
      const { error: apiError } = await client.POST(`/api/projects/${projectId}/kb/location/bulk-confirm`, {
        body: { entity_ids: ids },
      });

      if (apiError) {
        throw new Error('Failed to bulk confirm locations');
      }

      setSelectedIds([]);
      await fetchLocations(1, false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }, [projectId, fetchLocations]);

  const mergeLocation = useCallback(async (sourceId: string, targetId: string): Promise<void> => {
    try {
      const { error: apiError } = await client.POST(`/api/projects/${projectId}/kb/location/${sourceId}/merge`, {
        body: { merge_with_id: targetId },
      });

      if (apiError) {
        throw new Error('Failed to merge locations');
      }

      await fetchLocations(1, false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }, [projectId, fetchLocations]);

  const fetchReferences = useCallback(async (id: string): Promise<KBLocationReferences | null> => {
    try {
      const { data, error: apiError } = await client.GET(`/api/projects/${projectId}/kb/location/${id}/references`);

      if (apiError) {
        throw new Error('Failed to fetch references');
      }

      return data as KBLocationReferences;
    } catch {
      return null;
    }
  }, [projectId]);

  const loadMore = useCallback(async () => {
    if (!hasMore || loading) return;
    await fetchLocations(page + 1, true);
  }, [hasMore, loading, page, fetchLocations]);

  const refetch = useCallback(async () => {
    await fetchLocations(1, false);
  }, [fetchLocations]);

  const handleSearchChange = useCallback((value: string) => {
    setSearch(value);
  }, []);

  const handleTypeFilterChange = useCallback((value: LocationType | undefined) => {
    setLocationType(value);
  }, []);

  const handleConfirm = useCallback((id: string) => {
    setPendingConfirmId(id);
    setConfirmDialogOpen(true);
  }, []);

  const handleReject = useCallback(async (id: string) => {
    await rejectLocation(id);
  }, [rejectLocation]);

  const handleBulkConfirm = useCallback((ids: string[]) => {
    setPendingBulkConfirmIds(ids);
    setBulkConfirmDialogOpen(true);
  }, []);

  const handleMerge = useCallback((sourceId: string) => {
    setPendingMergeSourceId(sourceId);
    setMergeDialogOpen(true);
  }, []);

  return {
    locations,
    tree,
    loading,
    error,
    hasMore,
    search,
    locationType,
    confirmed,
    selectedIds,
    confirmDialogOpen,
    bulkConfirmDialogOpen,
    mergeDialogOpen,
    pendingConfirmId,
    pendingBulkConfirmIds,
    pendingMergeSourceId,
    locationsMap,
    setSearch,
    setLocationType,
    setConfirmed,
    setSelectedIds,
    createLocation,
    updateLocation,
    deleteLocation,
    confirmLocation,
    rejectLocation,
    bulkConfirm,
    mergeLocation,
    fetchReferences,
    loadMore,
    refetch,
    setConfirmDialogOpen,
    setBulkConfirmDialogOpen,
    setMergeDialogOpen,
    setPendingConfirmId,
    setPendingBulkConfirmIds,
    setPendingMergeSourceId,
    handleSearchChange,
    handleTypeFilterChange,
    handleConfirm,
    handleReject,
    handleBulkConfirm,
    handleMerge,
  };
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, waitFor } from '@testing-library/react';
import { Editor } from '../components/Editor';

// Mock @tiptap/react - must be before any imports that use it
const mockUseEditor = vi.fn();

vi.mock('@tiptap/react', () => ({
  useEditor: (...args: unknown[]) => mockUseEditor(...args),
  EditorContent: ({ editor, className }: { editor: unknown; className?: string }) => (
    <div data-testid="editor-content" data-editor={editor ? 'initialized' : 'null'} className={className}>
      {editor ? <div className="ProseMirror">Editor Content</div> : 'No Editor'}
    </div>
  ),
}));

// Mock editorConfig
vi.mock('../utils/editorConfig', () => ({
  useTipTapEditor: vi.fn((options) => {
    return mockUseEditor({
      content: options?.initialContent || '',
      editable: options?.editable ?? true,
      onUpdate: options?.onUpdate ? ({ editor }: { editor: { getJSON: () => unknown } }) => {
        options.onUpdate?.(JSON.stringify(editor.getJSON()));
      } : undefined,
    });
  }),
}));

describe('Editor', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should render loading skeleton when editor is not initialized', () => {
    mockUseEditor.mockReturnValue(null);

    render(<Editor />);

    // Loading state should be visible (skeleton has animate-pulse class)
    const skeleton = document.querySelector('.animate-pulse');
    expect(skeleton).toBeInTheDocument();
  });

  it('should render editor when initialized', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p>Test content</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Test content' }] }] })),
      isEditable: true,
    };

    mockUseEditor.mockReturnValue(mockEditor);

    render(<Editor />);

    // Editor content should be rendered
    expect(document.querySelector('.ProseMirror')).toBeInTheDocument();
  });

  it('should pass initialContent to useTipTapEditor', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p>Initial content</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Initial content' }] }] })),
    };

    mockUseEditor.mockReturnValue(mockEditor);
    const initialContent = '<p>Initial content</p>';

    render(<Editor initialContent={initialContent} />);

    expect(mockUseEditor).toHaveBeenCalledWith(
      expect.objectContaining({
        content: initialContent,
      })
    );
  });

  it('should pass editable prop to useTipTapEditor', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p>Content</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [] })),
    };

    mockUseEditor.mockReturnValue(mockEditor);

    render(<Editor editable={false} />);

    expect(mockUseEditor).toHaveBeenCalledWith(
      expect.objectContaining({
        editable: false,
      })
    );
  });

  it('should call onChange when content updates', async () => {
    const mockOnChange = vi.fn();
    let capturedOnUpdate: (({ editor }: { editor: { getJSON: () => unknown } }) => void) | undefined;

    const mockEditor = {
      getHTML: vi.fn(() => '<p>Test content</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Test content' }] }] })),
    };

    mockUseEditor.mockImplementation((options) => {
      capturedOnUpdate = options?.onUpdate;
      return mockEditor;
    });

    render(<Editor onChange={mockOnChange} />);

    // Simulate content update
    if (capturedOnUpdate) {
      capturedOnUpdate({ 
        editor: { 
          getJSON: () => ({ 
            type: 'doc', 
            content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Updated content' }] }] 
          }) 
        } 
      });
    }

    await waitFor(() => {
      expect(mockOnChange).toHaveBeenCalledWith(
        '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Updated content"}]}]}'
      );
    });
  });

  it('should use default initialContent when not provided', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p></p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [] })),
    };

    mockUseEditor.mockReturnValue(mockEditor);

    render(<Editor />);

    expect(mockUseEditor).toHaveBeenCalledWith(
      expect.objectContaining({
        content: '',
      })
    );
  });

  it('should use default editable value when not provided', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p></p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [] })),
    };

    mockUseEditor.mockReturnValue(mockEditor);

    render(<Editor />);

    expect(mockUseEditor).toHaveBeenCalledWith(
      expect.objectContaining({
        editable: true,
      })
    );
  });

  it('should not call onChange if not provided when content updates', async () => {
    let capturedOnUpdate: (({ editor }: { editor: { getJSON: () => unknown } }) => void) | undefined;

    const mockEditor = {
      getHTML: vi.fn(() => '<p>Test content</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Test content' }] }] })),
    };

    mockUseEditor.mockImplementation((options) => {
      capturedOnUpdate = options?.onUpdate;
      return mockEditor;
    });

    // Should not throw when onChange is not provided
    render(<Editor />);

    // Simulate content update
    if (capturedOnUpdate) {
      expect(() => {
        capturedOnUpdate!({ editor: { getJSON: () => ({ type: 'doc', content: [] }) } });
      }).not.toThrow();
    }
  });

  it('should apply correct CSS classes to editor container', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p>Test</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Test' }] }] })),
    };

    mockUseEditor.mockReturnValue(mockEditor);

    render(<Editor />);

    const container = document.querySelector('.bg-white');
    expect(container).toBeInTheDocument();
    expect(container).toHaveClass('rounded-lg', 'border', 'border-gray-200', 'shadow-sm');
  });

  it('should have min-height class on editor content', () => {
    const mockEditor = {
      getHTML: vi.fn(() => '<p>Test</p>'),
      getJSON: vi.fn(() => ({ type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Test' }] }] })),
    };

    mockUseEditor.mockReturnValue(mockEditor);

    render(<Editor />);

    const editorContent = document.querySelector('[class*="min-h-"]');
    expect(editorContent).toBeInTheDocument();
  });
});

