import { useState, useCallback, useEffect } from 'react';
import {
  DndContext,
  DragOverlay,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragStartEvent,
  type DragEndEvent,
  type DragOverEvent,
} from '@dnd-kit/core';
import {
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from '@dnd-kit/sortable';
import { FileText } from 'lucide-react';
import { useChapterPanel, type ChapterSummary } from '../../hooks/useChapterPanel';
import { ChapterTree } from './ChapterTree';
import { ChapterContextMenu } from './ChapterContextMenu';
import { NewChapterButton } from './NewChapterButton';
import { SkeletonLoader } from '../../../../components/ui/SkeletonLoader';
import { ErrorAlert } from '../../../../components/ui/ErrorAlert';

interface ChapterPanelProps {
  projectId: string;
  activeChapterId: string | null;
  onChapterSelect: (chapterId: string) => void;
  onChapterCreate?: (params: { volumeId: string; title?: string; targetOrder?: number }) => void;
  onChapterRename?: (chapterId: string, newTitle: string) => void;
  onChapterDelete?: (chapterId: string) => void;
  onChapterReorder?: (params: {
    chapterId: string;
    targetVolumeId: string;
    targetOrder: number;
  }) => void;
}

export function ChapterPanel({
  projectId,
  activeChapterId,
  onChapterSelect,
  onChapterCreate,
  onChapterRename,
  onChapterDelete,
  onChapterReorder,
}: ChapterPanelProps) {
  const {
    volumes,
    loading,
    error,
    refetch,
    createChapter,
    renameChapter,
    deleteChapter,
    reorderChapter,
  } = useChapterPanel({ projectId });

  const [expandedVolumeIds, setExpandedVolumeIds] = useState<Set<string>>(new Set());
  const [editingChapterId, setEditingChapterId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [activeDragId, setActiveDragId] = useState<string | null>(null);

  const [contextMenu, setContextMenu] = useState<{
    isOpen: boolean;
    position: { x: number; y: number };
    chapter: ChapterSummary | null;
  }>({
    isOpen: false,
    position: { x: 0, y: 0 },
    chapter: null,
  });

  useEffect(() => {
    if (volumes.length > 0) {
      setExpandedVolumeIds(new Set(volumes.map((v) => v.id)));
    }
  }, [volumes]);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  const handleToggleVolume = useCallback((volumeId: string) => {
    setExpandedVolumeIds((prev) => {
      const next = new Set(prev);
      if (next.has(volumeId)) {
        next.delete(volumeId);
      } else {
        next.add(volumeId);
      }
      return next;
    });
  }, []);

  const handleChapterContextMenu = useCallback((e: React.MouseEvent, chapter: ChapterSummary) => {
    e.preventDefault();
    setContextMenu({
      isOpen: true,
      position: { x: e.clientX, y: e.clientY },
      chapter,
    });
  }, []);

  const handleCloseContextMenu = useCallback(() => {
    setContextMenu((prev) => ({ ...prev, isOpen: false }));
  }, []);

  const handleRenameClick = useCallback(() => {
    if (contextMenu.chapter) {
      setEditingChapterId(contextMenu.chapter.id);
      setEditValue(contextMenu.chapter.title);
    }
  }, [contextMenu.chapter]);

  const handleRenameSubmit = useCallback(async (chapterId: string, newTitle: string) => {
    if (!newTitle.trim() || newTitle === contextMenu.chapter?.title) {
      setEditingChapterId(null);
      return;
    }

    const success = await renameChapter(chapterId, newTitle.trim());
    if (success) {
      onChapterRename?.(chapterId, newTitle.trim());
    }
    setEditingChapterId(null);
  }, [contextMenu.chapter, renameChapter, onChapterRename]);

  const handleRenameCancel = useCallback(() => {
    setEditingChapterId(null);
    setEditValue('');
  }, []);

  const handleDeleteClick = useCallback(async () => {
    if (contextMenu.chapter) {
      const success = await deleteChapter(contextMenu.chapter.id);
      if (success) {
        onChapterDelete?.(contextMenu.chapter.id);
      }
    }
  }, [contextMenu.chapter, deleteChapter, onChapterDelete]);

  const handleInsertAbove = useCallback(async () => {
    if (contextMenu.chapter) {
      const newChapter = await createChapter({
        volumeId: contextMenu.chapter.volumeId,
        targetOrder: contextMenu.chapter.order,
      });
      if (newChapter) {
        onChapterCreate?.({
          volumeId: contextMenu.chapter.volumeId,
          targetOrder: contextMenu.chapter.order,
        });
        setEditingChapterId(newChapter.id);
        setEditValue(newChapter.title);
      }
    }
  }, [contextMenu.chapter, createChapter, onChapterCreate]);

  const handleInsertBelow = useCallback(async () => {
    if (contextMenu.chapter) {
      const newChapter = await createChapter({
        volumeId: contextMenu.chapter.volumeId,
        targetOrder: contextMenu.chapter.order + 1,
      });
      if (newChapter) {
        onChapterCreate?.({
          volumeId: contextMenu.chapter.volumeId,
          targetOrder: contextMenu.chapter.order + 1,
        });
        setEditingChapterId(newChapter.id);
        setEditValue(newChapter.title);
      }
    }
  }, [contextMenu.chapter, createChapter, onChapterCreate]);

  const handleNewChapter = useCallback(async () => {
    if (volumes.length === 0) return;

    const lastVolume = volumes[volumes.length - 1];
    const newChapter = await createChapter({
      volumeId: lastVolume.id,
      title: '新章节',
    });

    if (newChapter) {
      onChapterCreate?.({
        volumeId: lastVolume.id,
        title: '新章节',
      });
      onChapterSelect(newChapter.id);
      setEditingChapterId(newChapter.id);
      setEditValue(newChapter.title);
    }
  }, [volumes, createChapter, onChapterCreate, onChapterSelect]);

  const handleDragStart = useCallback((event: DragStartEvent) => {
    setActiveDragId(event.active.id as string);
  }, []);

  const handleDragOver = useCallback((event: DragOverEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    const activeData = active.data.current;
    const overData = over.data.current;

    if (activeData?.type === 'chapter' && overData?.type === 'chapter') {
      const activeChapter = activeData.chapter as ChapterSummary;
      const overChapter = overData.chapter as ChapterSummary;

      if (activeChapter.volumeId !== overChapter.volumeId) {
        setExpandedVolumeIds((prev) => new Set([...prev, overChapter.volumeId]));
      }
    }
  }, []);

  const handleDragEnd = useCallback(async (event: DragEndEvent) => {
    const { active, over } = event;
    setActiveDragId(null);

    if (!over || active.id === over.id) return;

    const activeData = active.data.current;
    const overData = over.data.current;

    if (activeData?.type === 'chapter' && overData?.type === 'chapter') {
      const activeChapter = activeData.chapter as ChapterSummary;
      const overChapter = overData.chapter as ChapterSummary;

      const success = await reorderChapter({
        chapterId: activeChapter.id,
        targetVolumeId: overChapter.volumeId,
        targetOrder: overChapter.order,
      });

      if (success) {
        onChapterReorder?.({
          chapterId: activeChapter.id,
          targetVolumeId: overChapter.volumeId,
          targetOrder: overChapter.order,
        });
      }
    }
  }, [reorderChapter, onChapterReorder]);

  if (loading) {
    return (
      <div className="h-full flex flex-col p-4" data-testid="chapter-panel-loading">
        <SkeletonLoader variant="card" className="h-8 w-32 mb-4" />
        <div className="space-y-2 flex-1">
          {[1, 2, 3].map((i) => (
            <SkeletonLoader key={i} variant="card" className="h-10" />
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="h-full flex flex-col p-4" data-testid="chapter-panel-error">
        <ErrorAlert error={error} />
        <button onClick={refetch} className="btn-secondary w-auto mt-4 px-4 mx-auto">
          重试
        </button>
      </div>
    );
  }

  const allChapterIds = volumes.flatMap((v) => v.chapters.map((c) => c.id));
  const activeDragChapter = volumes
    .flatMap((v) => v.chapters)
    .find((c) => c.id === activeDragId);

  return (
    <div className="h-full flex flex-col bg-parchment">
      <div className="flex items-center justify-between px-4 py-3 border-b border-border/30">
        <h2 className="text-sm font-semibold text-ink">章节</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-4">
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragStart={handleDragStart}
          onDragOver={handleDragOver}
          onDragEnd={handleDragEnd}
        >
          <SortableContext
            items={allChapterIds}
            strategy={verticalListSortingStrategy}
          >
            <ChapterTree
              volumes={volumes}
              activeChapterId={activeChapterId}
              editingChapterId={editingChapterId}
              editValue={editValue}
              expandedVolumeIds={expandedVolumeIds}
              onToggleVolume={handleToggleVolume}
              onChapterSelect={onChapterSelect}
              onChapterContextMenu={handleChapterContextMenu}
              onChapterRenameSubmit={handleRenameSubmit}
              onChapterRenameCancel={handleRenameCancel}
              onEditValueChange={setEditValue}
            />
          </SortableContext>

          <DragOverlay>
            {activeDragChapter ? (
              <div className="bg-white rounded-md shadow-float p-3 opacity-90">
                <div className="flex items-center gap-2">
                  <FileText size={14} className="text-amber/60" />
                  <span className="text-sm font-medium text-ink">
                    {activeDragChapter.title}
                  </span>
                </div>
              </div>
            ) : null}
          </DragOverlay>
        </DndContext>
      </div>

      <div className="p-4 border-t border-border/30">
        <NewChapterButton
          onClick={handleNewChapter}
          disabled={volumes.length === 0}
        />
      </div>

      <ChapterContextMenu
        isOpen={contextMenu.isOpen}
        position={contextMenu.position}
        onClose={handleCloseContextMenu}
        onRename={handleRenameClick}
        onInsertAbove={handleInsertAbove}
        onInsertBelow={handleInsertBelow}
        onDelete={handleDeleteClick}
      />
    </div>
  );
}

import { useState } from 'react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import {
  GripVertical,
  ChevronDown,
  ChevronRight,
  Folder,
  FileText,
  CheckCircle2,
  Loader2,
  AlertCircle,
  XCircle,
  Minus,
} from 'lucide-react';
import type { ChapterSummary, Volume } from '../../hooks/useChapterPanel';

interface ChapterTreeItemProps {
  chapter: ChapterSummary;
  isActive: boolean;
  isEditing: boolean;
  editValue: string;
  onSelect: () => void;
  onContextMenu: (e: React.MouseEvent) => void;
  onRenameSubmit: (newTitle: string) => void;
  onRenameCancel: () => void;
  onEditValueChange: (value: string) => void;
}

function ChapterTreeItem({
  chapter,
  isActive,
  isEditing,
  editValue,
  onSelect,
  onContextMenu,
  onRenameSubmit,
  onRenameCancel,
  onEditValueChange,
}: ChapterTreeItemProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: chapter.id, data: { type: 'chapter', chapter } });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  const getParserStatusIcon = () => {
    switch (chapter.parserStatus) {
      case 'parsed':
        return <CheckCircle2 size={12} className="text-success" aria-label="已解析" />;
      case 'parsing':
        return <Loader2 size={12} className="text-amber animate-spin" aria-label="解析中" />;
      case 'pending':
        return <AlertCircle size={12} className="text-warning" aria-label="待解析" />;
      case 'failed':
        return <XCircle size={12} className="text-error" aria-label="解析失败" />;
      case 'empty':
      default:
        return <Minus size={12} className="text-ink-light/50" aria-label="无内容" />;
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      onRenameSubmit(editValue);
    } else if (e.key === 'Escape') {
      onRenameCancel();
    }
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      data-testid={`chapter-item-${chapter.id}`}
      className={`group flex items-center gap-2 px-3 py-2 cursor-pointer transition-colors ${
        isActive
          ? 'bg-amber-light/20 border-l-2 border-l-amber'
          : 'hover:bg-amber-light/10 border-l-2 border-l-transparent'
      }`}
      onClick={onSelect}
      onContextMenu={onContextMenu}
    >
      <button
        className="text-ink-light/40 hover:text-ink-light cursor-grab active:cursor-grabbing opacity-0 group-hover:opacity-100 transition-opacity"
        aria-label="拖动排序"
        {...attributes}
        {...listeners}
      >
        <GripVertical size={14} />
      </button>

      <FileText size={14} className="text-amber/60 flex-shrink-0" />

      {isEditing ? (
        <input
          type="text"
          value={editValue}
          onChange={(e) => onEditValueChange(e.target.value)}
          onKeyDown={handleKeyDown}
          onBlur={() => onRenameSubmit(editValue)}
          onClick={(e) => e.stopPropagation()}
          className="flex-1 px-2 py-0.5 text-sm bg-white border border-amber rounded focus:outline-none focus:ring-1 focus:ring-amber"
          maxLength={50}
          autoFocus
        />
      ) : (
        <span className="flex-1 text-sm text-ink truncate">{chapter.title}</span>
      )}

      <div className="flex items-center gap-2 text-xs text-ink-light">
        {chapter.charCount > 0 && (
          <span className="font-mono">{chapter.charCount.toLocaleString()}字</span>
        )}
        {getParserStatusIcon()}
      </div>
    </div>
  );
}

interface VolumeTreeItemProps {
  volume: Volume;
  isExpanded: boolean;
  activeChapterId: string | null;
  editingChapterId: string | null;
  editValue: string;
  onToggle: () => void;
  onChapterSelect: (chapterId: string) => void;
  onChapterContextMenu: (e: React.MouseEvent, chapter: ChapterSummary) => void;
  onChapterRenameSubmit: (chapterId: string, newTitle: string) => void;
  onChapterRenameCancel: () => void;
  onEditValueChange: (value: string) => void;
}

function VolumeTreeItem({
  volume,
  isExpanded,
  activeChapterId,
  editingChapterId,
  editValue,
  onToggle,
  onChapterSelect,
  onChapterContextMenu,
  onChapterRenameSubmit,
  onChapterRenameCancel,
  onEditValueChange,
}: VolumeTreeItemProps) {
  return (
    <div className="border-b border-border/20 last:border-b-0">
      <button
        onClick={onToggle}
        className="w-full flex items-center gap-2 px-3 py-2.5 hover:bg-amber-light/10 transition-colors text-left"
        aria-expanded={isExpanded}
        aria-label={isExpanded ? `折叠${volume.name}` : `展开${volume.name}`}
      >
        {isExpanded ? (
          <ChevronDown size={16} className="text-ink-light" />
        ) : (
          <ChevronRight size={16} className="text-ink-light" />
        )}
        <Folder size={16} className="text-amber/70 flex-shrink-0" />
        <span className="flex-1 text-sm font-medium text-ink truncate">{volume.name}</span>
        <span className="text-xs text-ink-light font-mono">
          {volume.chapterCount}章
        </span>
      </button>

      {isExpanded && (
        <div className="bg-parchment/20">
          {volume.chapters.map((chapter) => (
            <ChapterTreeItem
              key={chapter.id}
              chapter={chapter}
              isActive={activeChapterId === chapter.id}
              isEditing={editingChapterId === chapter.id}
              editValue={editValue}
              onSelect={() => onChapterSelect(chapter.id)}
              onContextMenu={(e) => onChapterContextMenu(e, chapter)}
              onRenameSubmit={(newTitle) => onChapterRenameSubmit(chapter.id, newTitle)}
              onRenameCancel={onChapterRenameCancel}
              onEditValueChange={onEditValueChange}
            />
          ))}
        </div>
      )}
    </div>
  );
}

interface ChapterTreeProps {
  volumes: Volume[];
  activeChapterId: string | null;
  editingChapterId: string | null;
  editValue: string;
  expandedVolumeIds: Set<string>;
  onToggleVolume: (volumeId: string) => void;
  onChapterSelect: (chapterId: string) => void;
  onChapterContextMenu: (e: React.MouseEvent, chapter: ChapterSummary) => void;
  onChapterRenameSubmit: (chapterId: string, newTitle: string) => void;
  onChapterRenameCancel: () => void;
  onEditValueChange: (value: string) => void;
}

export function ChapterTree({
  volumes,
  activeChapterId,
  editingChapterId,
  editValue,
  expandedVolumeIds,
  onToggleVolume,
  onChapterSelect,
  onChapterContextMenu,
  onChapterRenameSubmit,
  onChapterRenameCancel,
  onEditValueChange,
}: ChapterTreeProps) {
  if (volumes.length === 0) {
    return (
      <div className="p-6 text-center">
        <p className="text-ink-light text-sm">暂无章节</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-md border border-border/30 overflow-hidden">
      {volumes.map((volume) => (
        <VolumeTreeItem
          key={volume.id}
          volume={volume}
          isExpanded={expandedVolumeIds.has(volume.id)}
          activeChapterId={activeChapterId}
          editingChapterId={editingChapterId}
          editValue={editValue}
          onToggle={() => onToggleVolume(volume.id)}
          onChapterSelect={onChapterSelect}
          onChapterContextMenu={onChapterContextMenu}
          onChapterRenameSubmit={onChapterRenameSubmit}
          onChapterRenameCancel={onChapterRenameCancel}
          onEditValueChange={onEditValueChange}
        />
      ))}
    </div>
  );
}

export type { ChapterSummary };

